import{_ as a,o as e,c as i,a0 as t}from"./chunks/framework.CWk8AOcY.js";const k=JSON.parse('{"title":"HTTPS 证书与域名解析","description":"","frontmatter":{},"headers":[],"relativePath":"guide/https-and-domain.md","filePath":"zh/guide/https-and-domain.md"}'),n={name:"guide/https-and-domain.md"};function o(p,s,l,d,h,r){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="https-证书与域名解析" tabindex="-1">HTTPS 证书与域名解析 <a class="header-anchor" href="#https-证书与域名解析" aria-label="Permalink to &quot;HTTPS 证书与域名解析&quot;">​</a></h1><p>本文说明 Cube Sandbox 中沙箱访问的域名机制，以及如何解决 <strong>HTTPS 证书</strong>和<strong>域名解析</strong>两类常见问题。</p><blockquote><p><strong>说明：</strong> TLS 配置仅影响客户端访问 CubeProxy 的方式。<code>E2B_API_URL</code> 始终指向 <strong>Cube API Server</strong>（默认端口 <code>3000</code>），与 CubeProxy 是独立的组件。</p></blockquote><hr><h2 id="沙箱域名机制" tabindex="-1">沙箱域名机制 <a class="header-anchor" href="#沙箱域名机制" aria-label="Permalink to &quot;沙箱域名机制&quot;">​</a></h2><p>E2B 客户端访问沙箱时，域名是<strong>动态生成</strong>的，格式如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;sandbox-service-port&gt;-&lt;sandboxId&gt;.&lt;domain&gt;</span></span></code></pre></div><p>例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>49983-1aa1fae8fb364edaa8203a7481995b4d.cube.app</span></span></code></pre></div><p>其中：</p><ul><li><code>sandbox-service-port</code>：沙箱内业务服务监听的端口（如 <code>49999</code>）</li><li><code>sandboxId</code>：沙箱唯一 ID</li><li><code>domain</code>：基础域名，默认为 <code>cube.app</code>，可通过 <code>--sandbox-domain</code> 自定义</li></ul><p>由于域名中的 <code>sandboxId</code> 部分随每个沙箱动态变化，<strong>E2B 客户端所在的网络环境必须具备泛域名（wildcard）解析能力</strong>，即将 <code>*.&lt;domain&gt;</code> 解析到 CubeProxy 所在机器的 IP。</p><h3 id="一键安装内置-coredns-体验用" tabindex="-1">一键安装内置 CoreDNS（体验用） <a class="header-anchor" href="#一键安装内置-coredns-体验用" aria-label="Permalink to &quot;一键安装内置 CoreDNS（体验用）&quot;">​</a></h3><p>Cube 一键安装脚本会在安装节点上启动一个 <strong>CoreDNS</strong> 服务，自动处理 <code>*.cube.app</code> 的泛解析，使你能在该机器上直接体验完整流程，无需额外配置 DNS。</p><blockquote><p><strong>注意：</strong> 内置 CoreDNS 仅供本机/快速体验使用，不适合生产环境或多机共享部署。</p></blockquote><h3 id="生产环境-自定义域名-自有-dns" tabindex="-1">生产环境：自定义域名 + 自有 DNS <a class="header-anchor" href="#生产环境-自定义域名-自有-dns" aria-label="Permalink to &quot;生产环境：自定义域名 + 自有 DNS&quot;">​</a></h3><p>生产环境中，建议使用自己的域名并配置泛解析 DNS 记录：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.your.domain.com  →  &lt;CubeProxy 所在节点的 IP&gt;</span></span></code></pre></div><p>然后在启动 Cube API Server 时通过启动参数或环境变量指定该域名：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动参数</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./cube-api</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sandbox-domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your.domain.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或环境变量</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CUBE_API_SANDBOX_DOMAIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your.domain.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./cube-api</span></span></code></pre></div><p>这样 API 响应中的 <code>domain</code> 字段会返回 <code>your.domain.com</code>，E2B SDK 才能正确构建沙箱访问地址。</p><hr><h2 id="https-证书配置" tabindex="-1">HTTPS 证书配置 <a class="header-anchor" href="#https-证书配置" aria-label="Permalink to &quot;HTTPS 证书配置&quot;">​</a></h2><p>CubeProxy 开箱提供 <strong>HTTPS（443 端口）和 HTTP（80 端口）</strong> 两种访问方式。E2B SDK 默认使用 HTTPS。Cube 一键安装已预装 <code>cube.app</code> 测试证书，可直接体验 HTTPS。</p><p>如需替换为自定义域名或生产证书，有以下几种方式：</p><h3 id="方式-a-—-mkcert-本地开发快速验证" tabindex="-1">方式 A — mkcert（本地开发快速验证） <a class="header-anchor" href="#方式-a-—-mkcert-本地开发快速验证" aria-label="Permalink to &quot;方式 A — mkcert（本地开发快速验证）&quot;">​</a></h3><p><code>mkcert</code> 可在几秒内为自定义域名生成本地可信证书：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkcert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkcert</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-host-ip-or-domai</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>设置 <code>SSL_CERT_FILE</code>，让 E2B SDK 信任生成的 CA：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SSL_CERT_FILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/root/.local/share/mkcert/rootCA.pem</span></span></code></pre></div><blockquote><p>mkcert 证书只在运行过 <code>mkcert -install</code> 的机器上受信任，不适合生产环境或多人共享部署。</p></blockquote><h3 id="方式-b-—-自有证书-域名-生产环境" tabindex="-1">方式 B — 自有证书 / 域名（生产环境） <a class="header-anchor" href="#方式-b-—-自有证书-域名-生产环境" aria-label="Permalink to &quot;方式 B — 自有证书 / 域名（生产环境）&quot;">​</a></h3><p>修改 CubeProxy 的 <code>nginx.conf</code>，使用正式证书和私钥：</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">443</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ssl;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your.domain.com;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ssl_certificate </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    /path/to/your/cert.pem;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ssl_certificate_key </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/your/key.pem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>同时通过 <code>--sandbox-domain</code> 告知 Cube API Server 对外域名（见上文「生产环境：自定义域名」章节）。</p><h3 id="方式-c-—-仅保留-https-关闭-http" tabindex="-1">方式 C — 仅保留 HTTPS（关闭 HTTP） <a class="header-anchor" href="#方式-c-—-仅保留-https-关闭-http" aria-label="Permalink to &quot;方式 C — 仅保留 HTTPS（关闭 HTTP）&quot;">​</a></h3><p>CubeProxy 默认同时监听 HTTP 和 HTTPS。如需完全关闭 HTTP 端口，删除 <code>nginx.conf</code> 中的 HTTP server block，并在 <code>docker-compose.yaml</code> 中去掉对应的端口映射即可。</p><blockquote><p>E2B SDK 仅使用 HTTPS，关闭 HTTP 不影响基于 SDK 的客户端。</p></blockquote><hr><h2 id="体验方案-e2b-dev-sidecar" tabindex="-1">体验方案：e2b-dev-sidecar <a class="header-anchor" href="#体验方案-e2b-dev-sidecar" aria-label="Permalink to &quot;体验方案：e2b-dev-sidecar&quot;">​</a></h2><p>如果你只是在本地开发环境中体验 Cube，不想配置泛解析 DNS，也不想处理自签证书信任问题，可以使用 <strong>e2b-dev-sidecar</strong> 方案。</p><p>该方案通过在本地启动一个轻量代理，拦截 E2B SDK 的数据面请求，在转发时自动改写 <code>Host</code> 头，从而：</p><ul><li><strong>绕过泛解析 DNS</strong>：本地无需配置 <code>*.cube.app</code> 解析</li><li><strong>绕过 HTTPS 证书</strong>：sidecar 默认不校验服务端证书（<code>CUBE_REMOTE_PROXY_VERIFY_SSL=false</code>）</li></ul><p>详见：<a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar" target="_blank" rel="noreferrer">e2b-dev-sidecar 示例</a></p><blockquote><p><strong>注意：</strong> e2b-dev-sidecar 是面向开发体验的最小实现，不适合生产环境。</p></blockquote>`,45)])])}const g=a(n,[["render",o]]);export{k as __pageData,g as default};
